function clearGameClip() {}

// === sprite.js ===
// src/ps2/sprite.js — Sprite system for PS2 AthenaEnv
// Lightweight sprite objects with atlas frame animation, position, scale, alpha

var spriteIdCounter = 0;

function createSprite(atlasName, frameName) {
    return {
        id: spriteIdCounter++,
        atlas: atlasName,
        frame: frameName,
        x: 0,
        y: 0,
        anchorX: 0.5,
        anchorY: 0.5,
        scaleX: 1.0,
        scaleY: 1.0,
        alpha: 1.0,
        rotation: 0,
        visible: 1,
        tint: null,
        // Animation
        frames: null,
        animFrame: 0,
        animSpeed: 0.15,
        animCounter: 0,
        animLoop: 1,
        animPlaying: 0,
        // Hit area (relative to sprite position)
        hitX: 0,
        hitY: 0,
        hitW: 0,
        hitH: 0,
    };
}

function createAnimSprite(atlasName, frameNames) {
    var spr = createSprite(atlasName, frameNames[0]);
    spr.frames = frameNames;
    spr.animPlaying = 1;
    // Set default hit area from first frame
    var size = getFrameSize(atlasName, frameNames[0]);
    spr.hitW = size.w;
    spr.hitH = size.h;
    return spr;
}

function updateSpriteAnim(spr) {
    if (!spr.animPlaying || !spr.frames || spr.frames.length <= 1) return;
    spr.animCounter += spr.animSpeed;
    if (spr.animCounter >= 1.0) {
        spr.animCounter -= 1.0;
        spr.animFrame++;
        if (spr.animFrame >= spr.frames.length) {
            if (spr.animLoop) {
                spr.animFrame = 0;
            } else {
                spr.animFrame = spr.frames.length - 1;
                spr.animPlaying = 0;
            }
        }
        spr.frame = spr.frames[spr.animFrame];
    }
}

function drawSprite(spr) {
    if (!spr.visible || spr.alpha <= 0) return;

    var tintColor = null;
    if (spr.tint) {
        tintColor = spr.tint;
    } else if (spr.alpha < 1.0) {
        var a = Math.floor(spr.alpha * 128);
        tintColor = Color.new(128, 128, 128, a);
    }

    // Convert game coords to screen coords
    var sx = toScreenX(spr.x);
    var sy = toScreenY(spr.y);
    var scX = spr.scaleX * SCALE;
    var scY = spr.scaleY * SCALE;

    drawFrame(spr.atlas, spr.frame, sx, sy, scX, scY, spr.alpha, tintColor);
}

// Draw sprite at game coordinates (no screen transform — for use within game-coord rendering)
function drawSpriteGame(spr) {
    if (!spr.visible || spr.alpha <= 0) return;

    var tintColor = null;
    if (spr.tint) {
        tintColor = spr.tint;
    } else if (spr.alpha < 1.0) {
        var a = Math.floor(spr.alpha * 128);
        tintColor = Color.new(128, 128, 128, a);
    }

    drawFrame(spr.atlas, spr.frame, spr.x, spr.y, spr.scaleX, spr.scaleY, spr.alpha, tintColor);
}

// AABB hit test between two sprites (using hitArea or frame size)
function hitTestSprites(a, b) {
    var aSize = getFrameSize(a.atlas, a.frame);
    var aw = a.hitW || aSize.w;
    var ah = a.hitH || aSize.h;
    var ax = a.x + a.hitX - aw * a.anchorX;
    var ay = a.y + a.hitY - ah * a.anchorY;

    var bSize = getFrameSize(b.atlas, b.frame);
    var bw = b.hitW || bSize.w;
    var bh = b.hitH || bSize.h;
    var bx = b.x + b.hitX - bw * b.anchorX;
    var by = b.y + b.hitY - bh * b.anchorY;

    return ax < bx + bw && ax + aw > bx && ay < by + bh && ay + ah > by;
}

// Hit test sprite vs rectangle {x, y, w, h}
function hitTestSpriteRect(spr, rect) {
    var sSize = getFrameSize(spr.atlas, spr.frame);
    var sw = spr.hitW || sSize.w;
    var sh = spr.hitH || sSize.h;
    var sx = spr.x + spr.hitX - sw * spr.anchorX;
    var sy = spr.y + spr.hitY - sh * spr.anchorY;

    return sx < rect.x + rect.w && sx + sw > rect.x && sy < rect.y + rect.h && sy + sh > rect.y;
}

// === tween.js ===
// src/ps2/tween.js — Simple tween system for PS2 AthenaEnv
// Replaces Phaser tweens with a frame-based interpolation system

var tweens = [];
var tweenIdCounter = 0;

function easeLinear(t) { return t; }
function easeQuintOut(t) { return 1 - Math.pow(1 - t, 5); }
function easeQuintIn(t) { return t * t * t * t * t; }
function easeExpoIn(t) { return t === 0 ? 0 : Math.pow(2, 10 * (t - 1)); }
function easeExpoOut(t) { return t === 1 ? 1 : 1 - Math.pow(2, -10 * t); }
function easeBackOut(t) { var s = 1.70158; return (t -= 1) * t * ((s + 1) * t + s) + 1; }
function easeElasticOut(t) {
    if (t === 0 || t === 1) return t;
    return Math.pow(2, -10 * t) * Math.sin((t - 0.075) * (2 * Math.PI) / 0.3) + 1;
}

var EASE_FUNCS = {
    "Linear": easeLinear,
    "Quint.easeOut": easeQuintOut,
    "Quint.easeIn": easeQuintIn,
    "Expo.easeIn": easeExpoIn,
    "Expo.easeOut": easeExpoOut,
    "Back.easeOut": easeBackOut,
    "Elastic.easeOut": easeElasticOut,
};

function getEase(name) {
    return EASE_FUNCS[name] || easeLinear;
}

// Create a tween
// opts: { target, props: {key: endVal}, duration, delay, ease, yoyo, repeat, onComplete, onUpdate }
function addTween(opts) {
    var id = tweenIdCounter++;
    var tw = {
        id: id,
        target: opts.target,
        props: {},
        duration: opts.duration || 300,
        delay: opts.delay || 0,
        elapsed: 0,
        ease: getEase(opts.ease || "Linear"),
        yoyo: opts.yoyo || 0,
        repeat: opts.repeat || 0,
        repeatCount: 0,
        forward: 1,
        onComplete: opts.onComplete || null,
        onUpdate: opts.onUpdate || null,
        active: 1,
        hold: opts.hold || 0,
        holdElapsed: 0,
    };

    // Store start/end values for each property
    var propKeys = Object.keys(opts.props || {});
    for (var i = 0; i < propKeys.length; i++) {
        var key = propKeys[i];
        tw.props[key] = {
            start: opts.target[key] !== undefined ? opts.target[key] : 0,
            end: opts.props[key],
        };
    }

    tweens.push(tw);
    return id;
}

function updateTweens(dt) {
    for (var i = tweens.length - 1; i >= 0; i--) {
        var tw = tweens[i];
        if (!tw.active) {
            tweens.splice(i, 1);
            continue;
        }

        // Handle delay
        if (tw.delay > 0) {
            tw.delay -= dt;
            if (tw.delay > 0) continue;
            dt = -tw.delay;
            tw.delay = 0;
        }

        tw.elapsed += dt;

        var progress = Math.min(tw.elapsed / tw.duration, 1.0);
        var easedProgress = tw.ease(tw.forward ? progress : 1 - progress);

        // Apply properties
        var propKeys = Object.keys(tw.props);
        for (var p = 0; p < propKeys.length; p++) {
            var key = propKeys[p];
            var prop = tw.props[key];
            tw.target[key] = prop.start + (prop.end - prop.start) * easedProgress;
        }

        if (tw.onUpdate) tw.onUpdate(tw.target, progress);

        if (progress >= 1.0) {
            if (tw.yoyo && tw.forward) {
                // Hold before reversing
                if (tw.hold > 0 && tw.holdElapsed < tw.hold) {
                    tw.holdElapsed += dt;
                    continue;
                }
                tw.forward = 0;
                tw.elapsed = 0;
                tw.holdElapsed = 0;
            } else if (tw.repeat !== 0) {
                tw.repeatCount++;
                if (tw.repeat === -1 || tw.repeatCount <= tw.repeat) {
                    tw.forward = 1;
                    tw.elapsed = 0;
                    tw.holdElapsed = 0;
                } else {
                    tw.active = 0;
                    if (tw.onComplete) tw.onComplete(tw.target);
                }
            } else {
                tw.active = 0;
                if (tw.onComplete) tw.onComplete(tw.target);
            }
        }
    }
}

function killTween(id) {
    for (var i = 0; i < tweens.length; i++) {
        if (tweens[i].id === id) {
            tweens[i].active = 0;
            break;
        }
    }
}

function killAllTweens() {
    tweens.length = 0;
}

// === timer.js ===
// src/ps2/timer.js — Delayed call / timer system for PS2 AthenaEnv
// Replaces Phaser scene.time.delayedCall() and scene.time.addEvent()

var timers = [];
var timerIdCounter = 0;

function delayedCall(delayMs, callback) {
    var id = timerIdCounter++;
    timers.push({
        id: id,
        delay: delayMs,
        elapsed: 0,
        callback: callback,
        repeat: 0,
        repeatCount: 0,
        interval: 0,
        active: 1,
    });
    return id;
}

function addTimerEvent(delayMs, repeatCount, callback) {
    var id = timerIdCounter++;
    timers.push({
        id: id,
        delay: delayMs,
        elapsed: 0,
        callback: callback,
        repeat: repeatCount,
        repeatCount: 0,
        interval: delayMs,
        active: 1,
    });
    return id;
}

function addLoopTimer(delayMs, callback) {
    return addTimerEvent(delayMs, -1, callback);
}

function removeTimer(id) {
    for (var i = 0; i < timers.length; i++) {
        if (timers[i].id === id) {
            timers[i].active = 0;
            break;
        }
    }
}

function updateTimers(dt) {
    for (var i = timers.length - 1; i >= 0; i--) {
        var t = timers[i];
        if (!t.active) {
            timers.splice(i, 1);
            continue;
        }

        t.elapsed += dt;
        if (t.elapsed >= t.delay) {
            t.callback();
            t.repeatCount++;

            if (t.repeat === 0) {
                // One-shot
                t.active = 0;
                timers.splice(i, 1);
            } else if (t.repeat === -1 || t.repeatCount <= t.repeat) {
                // Repeating
                t.elapsed -= t.delay;
            } else {
                // Done repeating
                t.active = 0;
                timers.splice(i, 1);
            }
        }
    }
}

function clearAllTimers() {
    timers.length = 0;
}

